sql:
SELECT COUNT(*) 
FROM voter_eligibility 
WHERE eligible = 1 AND eligibility_criteria = '18 years or older, citizen of Country X';

SELECT voter_id, eligible 
FROM voter_eligibility 
WHERE eligible = 0;

SELECT AVG(T1.area) AS average_area
FROM regions T1
WHERE T1.population > (SELECT AVG(population) FROM regions);

SELECT COUNT(vote_id) 
FROM voter_votes 
WHERE voter_verification_method = 'Biometric' AND vote_type = 'absentee';

external_knowledge:
- 'Region 1' is a specific administrative area within a country;
- 'Primary contact method' refers to the preferred method of communication for the voter;
- 'Consent given' indicates that the voter has agreed to data sharing or communication;
- 'Verified documents' are official documents that have been authenticated;
- 'Sent notification' means that a notification (e.g., registration confirmation, voting reminder) has been successfully delivered to the voter.

sql:
SELECT COUNT(DISTINCT voter_id) AS unique_voters
FROM voter_consents
WHERE consent_type = 'data_sharing' AND consent_given = 1;

SELECT COUNT(voter_id) AS view_count
FROM voter_access_logs
WHERE access_type = 'view';

SELECT COUNT(vote_id) AS number_of_votes
FROM voter_votes
WHERE election_id = (SELECT MAX(election_id) FROM elections);

SELECT COUNT(flag_id) 
FROM voter_flags 
WHERE flag_type = 'suspicious activity' AND resolved = 0;

SELECT voter_id
FROM voter_contacts
WHERE contact_type = 'email' AND contact_value = 'john.doe@example.com';

SELECT COUNT(DISTINCT voter_id) AS TotalVerifiedVoters
FROM voter_votes
WHERE voter_verification_method = 'ID card';

external_knowledge:
- Eligible voters are those who meet the eligibility criteria of being 18 years or older and citizens of Country X;
- Communication consent is necessary for the voter to be included in the count;
- Primary email is the only contact method considered for this query;
- The voter must be associated with a specific region in an election.

sql:
SELECT COUNT(DISTINCT voter_id) AS number_of_voters_notified
FROM voter_notifications
WHERE notification_type = 'voting_reminder' AND notification_status = 'sent';

SELECT COUNT(voter_id) 
FROM voter_consents 
WHERE consent_type = 'data_sharing' AND consent_given = 1;

SELECT voter_id, consent_type, consent_given
FROM voter_consents
WHERE consent_given = 0 AND consent_date > '2023-01-01';

SELECT voter_id, document_type, verified 
FROM voter_documents 
WHERE verified = 0;

SELECT COUNT(voter_id) 
FROM voter_contacts 
WHERE contact_type = 'phone' AND primary_contact = 1;

SELECT 
    CAST(
        SUM(CASE WHEN eligible = 1 THEN 1 ELSE 0 END) AS REAL
    ) * 100 / COUNT(DISTINCT voter_id) AS eligible_percentage
FROM voter_eligibility;

SELECT COUNT(DISTINCT voter_id) 
FROM voter_documents 
WHERE verified = 1;

SELECT voter_id, flag_type, flag_details, flag_date
FROM voter_flags
WHERE resolved = 0 AND flag_type = 'suspicious_activity';
